// Use fetch directly — bypasses the global axios interceptors so no auth
// machinery or error toasts fire for these public endpoints.
const base = import.meta.env.VITE_API_BASE_URL as string;

async function get<T>(path: string, timeoutMs?: number): Promise<T> {
  const controller = new AbortController();
  const id = timeoutMs !== undefined ? setTimeout(() => controller.abort(), timeoutMs) : undefined;
  try {
    const res = await fetch(`${base}${path}`, { signal: controller.signal });
    if (!res.ok) throw new Error(`${res.status}`);
    return res.json();
  } finally {
    if (id !== undefined) clearTimeout(id);
  }
}

export interface AboutInfo {
  version: string;
  commit: string;
  commitUrl: string;
  builtAt: string;
  appStartedAt: string;
  appRunningSince: string;
  environment: string;
}

export interface HealthInfo {
  status: 'Healthy' | 'Degraded' | 'Unhealthy';
  appStartedAt: string;
  appRunningSince: string;
  components: Record<string, unknown>;
}

export const aboutService = {
  getAbout: () => get<AboutInfo>('/about'),
  getHealth: () => get<HealthInfo>('/health/live', 10_000),
};
